def perceive(data):
    out = {}
    text = data if isinstance(data, str) else str(data)
    for line in text.splitlines():
        if "=" not in line:
            continue
        key, _, value = line.partition("=")
        key = key.strip()
        value = value.strip()
        if key == "rpo_target":
            try:
                out["rpo_target"] = int(value)
            except (ValueError, TypeError):
                pass
    return out
